61 ሲሆን ከዚህ ቀደም በነበሩት ዓመታት ሲጠራቀም የመጣውን የተሰብሳቢ ሂሳብ በዝርዝር በማውጣትና ማወራረድ ስራ የጀመርን ሲሆን በቀጣይ በ4ኛ ሩብ ዓመት አስተካክለን የምናቀርብ ይሆናል፡፡\r\nእስካሁን ተመዝግቦ ከታየው የተከፋይ ብር 75,153,340.71 ውስጥ ብር 20,272,833.00 ተወራርዶ ቀሪ ያልተወራረደ ብር 54,880,507.71 ሲሆን በቀጣይ ሩብ ዓመት የተከፋይ ሂሳቡን በእጅጉ ለመቀነስ እቅድ አውጥተን እየሰራን እንገኛለን፡፡\r\nገቢው ከአንድነት ፓርክ ውሰጥ ከሚገኙ ሱቆች ኪራይ ተሰብስቦ በዝግ አካውንት ገቢ የተደረገ ሲሆን በቀጣይ ይህንን ጉዳይ በዘላቂነት ለመፍታት ጉዳዩ ከሚመለከታቸው የተቋማት ኃላፊዎች ጋር ለመነጋገር ጥረት እየተደረገ በመሆኑ አፈጻጸሙ የምናሳውቅ ይሆናል፡፡ \r\n','Report','approved','default','___ ___ ___.docx','C:/AMSReports/ateshome@mofed.gov.et/___ ___ ___.docx',NULL,1,'11002',90,'Audit-09',113,90),(255,'muluneh1228@gmail.com','2024-07-05 13:37:24.000000','ateshome@mofed.gov.et','2024-09-02 17:17:56.000000',NULL,NULL,NULL,'Prime minister office.doc','C:/AMSReports/muluneh1228@gmail.com/Prime minister office.doc',NULL,NULL,NULL,'','Report','approved','Yes','Prime minister office.doc','C:/AMSReports/ateshome@mofed.gov.et/Prime minister office.doc',NULL,1,'11002',90,'Audit-010',113,90),(257,'azeb834@gmail.com','2024-07-09 11:53:46.000000','akebede@mofed.gov.et','2025-02-05 15:45:16.000000',NULL,NULL,NULL,'H.T (1).rar','C:/AMSReports/azeb834@gmail.com/H.T (1).rar',NULL,NULL,NULL,'','Report','approved','default','H.T (1).rar','C:/AMSReports/akebede@mofed.gov.et/H.T (1).rar',NULL,3,'11018',82,'Audit-02',112,82),(258,'tsehayabebe52@yahoo.com','2024-07-09 13:32:25.000000','akebede@mofed.gov.et','2025-03-27 16:57:59.000000',NULL,NULL,NULL,'annual plan 2017.pdf','C:/AMSReports/tsehayabebe52@yahoo.com/annual plan 2017.pdf',NULL,NULL,NULL,'','Report','approved','default','annual plan 2017.pdf','C:/AMSReports/akebede@mofed.gov.et/annual plan 2017.pdf',NULL,1,'11215',62,'Audit-02',72,62),(259,'tsehayabebe52@yahoo.com','2024-07-09 16:24:05.000000','akebede@mofed.gov.et','2025-03-27 16:58:22.000000',NULL,NULL,NULL,'annual plan 2017.pdf','C:/AMSReports/tsehayabebe52@yahoo.com/annual plan 2017.pdf',NULL,NULL,NULL,'','Report','approved','default','annual plan 2017.pdf','C:/AMSReports/akebede@mofed.gov