SReports/tatekbekele1216@gmail.com/AABE Q4.1.2.zip',NULL,NULL,NULL,'','Report','approved','default','AABE Q4.1.2.zip','C:/AMSReports/akebede@mofed.gov.et/AABE Q4.1.2.zip',NULL,3,'11337',82,'Audit-06',128,82),(376,'tatekbekele1216@gmail.com','2024-11-08 10:29:52.000000','akebede@mofed.gov.et','2025-02-05 15:46:00.000000',NULL,NULL,NULL,'H.T (1).rar','C:/AMSReports/tatekbekele1216@gmail.com/H.T (1).rar',NULL,NULL,NULL,'','Report','approved','default','H.T (1).rar','C:/AMSReports/akebede@mofed.gov.et/H.T (1).rar',NULL,1,'11337',82,'Audit-06',128,82),(377,'tatekbekele1216@gmail.com','2024-11-08 14:44:52.000000','akebede@mofed.gov.et','2025-03-04 11:27:55.000000',NULL,NULL,NULL,'AABE Q4.1.2.zip','C:/AMSReports/tatekbekele1216@gmail.com/AABE Q4.1.2.zip',NULL,NULL,NULL,'\r\nአዲስ አበባ\r\nጉዳዩ፡- የ2016 በጀት 4ኛ እና የ2017 1ኛ ሩብ ዓመት የኦዲት ሪፖርት\r\nላይ አስተያየት መስጠትን ይመለከታል፡፡\r\nከላይ የተገለጸው የኦዲት ውጤት አስመልክቶ በቁጥር ኢሂኦቦ/265/17 በቀን 28/02/2017 ዓ.ም በተፃፈ ደብዳቤ ለዋና ዳይሬክተር ሲቀርብ ግልባጭ የተደረገልን ሪፖርት ተገምግሞ በታዩት የአሰራር ክፍተቶች ላይ ትኩረት ተሰጥቶ የእርምት እርምጃ እንዲወሰድ የሚከተለው አስተያየት ተሰጥቷል፡፡\r\nየኦዲት ሪፖርት ማቅረቢያ ጊዜ፡-\r\nየኦዲት ሪፖርት በየሩብ ዓመቱ እንዲቀርብ ያስፈለገበት ምክንያት ተቋማት በየወሩ የሚተላለፍላቸውን በጀት በአግባቡ ስራ ላይ መዋሉን በማረጋገጥ እና በወቅቱ ለሚታዩ የአሰራር ክፍተቶች ወቅታዊ የእርምት እምርጃ በመውሰድ ውጤታማ የሆነ የበጀት አጠቃቀም እንዲኖር ለማስቻል ነው፡፡ ሆኖም የ4ኛ ሩብ ዓመት ነሀሴ 30/2016 መቅረብ ያለበት ሲሆን 28/02/2017 ዓ.ም መቅረቡ ወቅቱን ያልጠበቀ እና የውስጥ ኦዲት መመሪያን ያልተከተለ መሆኑ ታውቆ የ2ኛ ሩብ ዓመት ሪፖርት በተያዘው እቅድ የማይቀርብ ከሆነ የፋይናንስ ኃላፊነትን በአግባቡ ባለመወጣት የሚወሰዱ አስተዳደራዊ እርምጃዎች መመሪያ ቁጥር 48/2009 አንቀጽ 11.2 ንዑስ ቁጥር 11.2.1 እስከ 11.2.6 ድረስ የተመለከቱትን በተጨማሪም የኦዲት ግኝት ባለማስተካከል አንቀጽ 12.2 ንዑስ ቁጥር 12.2.1 እስከ 12.2.6 ድረስ በተዘረዘረው መሰረት ከጽሁፍ ማስጠንቀቂያ ጀምሮ እስከ ገንዘብ ቅጣት እንዲሁም ከኃላፊነት እስከ ማስነሳት የሚደርስ እርምጃ ለመውሰድ የምንገደድ መሆኑን እንገልፃለን፡፡\r\nየተቋሙ የበላይ አመራር የሰጡትን አቅጣጫ በተመለከተ፡-\r\n•	በመውጫ ስብሰባ ቃለ ጉባኤ ላይ የበላይ አመራር የማይነበቡ የፈጣን መንገድ ደረሰኞች በጊዜ ብዛት የህትመት ጥራት የማይታዩ የክፍያ ደረሰኞች ጀርባው ላይ ባለጉዳዩ እንዲፈርም እና የሚመራው ማመልከቻ ላይ ደግሞ የቅርብ ኃላፊ በመፈረም ማረጋገጫ መስጠት ያለበት መሆኑ፣\r\n•	ለስልጠና አገልግሎት የምንጠቀመው የነዳጅ ፍጆታ ከመደበኛ ትራንሰፖርት በጀት ላይ መወሰድ የሌለበት መሆኑን እና የግዥና ፋይናንስ ከመሰረታዊ አገልግሎት ጋር በመሆን  እንዲሰሩ  በመግለጽ  በሰጡት አቅጣጫ መሠረት ተስተካክሎ ውጤቱ እንዲገለጽልን፡፡ \r\nበሩብ ዓመት በተገኙ ግኝቶች ላይ ግብረ-መልስ እንዲቀርብ እያሳሰብን ግኝቶችን የያዘ 1 ገጽ አባሪ ከዚህ ሸኚ ደብዳቤ ጋር አያይዘን ልከናል፡፡  \r\n                                                                                                  \r\n                                                               ከሠላምታ ጋር\r\nእንዲያውቁት፡-\r\n	ለኢንስፔክሽን መምሪያ\r\nግልባጭ፡-\r\n	ለውስጥ ኦዲት ዳይሬክቶሬት\r\n\r\n\r\n\r\n\r\n','Report','approved','Yes','AABE Q4.1.2.zip','C:/AMSReports/akebede@mofed.gov.et/AABE Q4.1.2.zip',NULL,1,'11337',82,'Audit-06',128,82),(378,'muluneh1228@gmail.com','2024-11-11 13:43:14.000000','ateshome@mofed.gov.et','2025-03-11 15:50:23.000000',NULL,NULL,NULL,'Unconfirmed 92826.crdownload','C:/AMSReports/muluneh1228@gmail.com/Unconfirmed 92826.crdownload',NULL,NULL,NULL,'','Report','approved','Yes','Unconfirmed 92826.crdownload','C:/AMSReports/ateshome@mofed.gov.et/Unconfirmed 92826.crdownload',NULL,1,'11002',90,'Audit-011',113,90),(379,'abensol86@gmail.com','2024-11-11 16:50:23.000000','ywolde@mofed.gov.et','2025-02-27 15:13:43.000000',NULL,NULL,NULL,'et lnstitution of the ombu 2017  1.pdf','C:/AMSReports/abensol86@gmail.com/et lnstitution of the ombu 2017  1.pdf',NULL,NULL,NULL,'','Report','approved','default','et lnstitution of the ombu 2017  1.pdf','C:/AMSReports/ywolde@mofed.gov.et/et lnstitution of the ombu 2017  1.pdf',NULL,3,'11026',91,'Audit-06',116,91),(380,'dessudessu57@gmail.com','2024-11-12 11:37:33.000000','ateshome@mofed.gov.et','2024-11-12 14:29:06.000000',NULL,NULL,NULL,'doc00000720240628113952.pdf','C:/AMSReports/dessudessu57@gmail.com/doc00000720240628113952.pdf',NULL,NULL,NULL,'','Report','approved','default','doc00000720240628113952.pdf','C:/AMSReports/ateshome@mofed.gov.et/doc00000720240628113952.pdf',NULL,3,'13001',83,'Audit-02',77,83),(381,'sabayewiabme852@gmail.com','2024-11-15 11:42:57.000000','akebede@mofed.gov.et','2025-03-27 16:57:09.000000',NULL,NULL,NULL,'MX-M5050_20241115_163848.pdf','C:/AMSReports/sabayewiabme852@gmail.com/MX-M5050_2024